static double SplitCost(size_t i, void *context)
/* clang-format off */
/* The context is a live SplitCostContext; its lz77 store must satisfy every
   obligation EstimateCost places on the two half-open ranges [start, i) and
   [i, end).  The split index i lies between start and end, so the union of the
   two ranges is exactly [start, end), and pinning the per-element bounds over
   [start, end) discharges both EstimateCost calls. */
__CPROVER_requires(__CPROVER_is_fresh(context, sizeof(SplitCostContext)))
__CPROVER_requires(__CPROVER_is_fresh(((SplitCostContext *)context)->lz77, sizeof(ZopfliLZ77Store)))
__CPROVER_requires(((SplitCostContext *)context)->start <= i)
__CPROVER_requires(i <= ((SplitCostContext *)context)->end)
__CPROVER_requires(((SplitCostContext *)context)->end <= ((SplitCostContext *)context)->lz77->size)
__CPROVER_requires(((SplitCostContext *)context)->lz77->size <= 3)
__CPROVER_requires(__CPROVER_is_fresh(((SplitCostContext *)context)->lz77->litlens, ((SplitCostContext *)context)->lz77->size * sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(((SplitCostContext *)context)->lz77->dists, ((SplitCostContext *)context)->lz77->size * sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(((SplitCostContext *)context)->lz77->pos, ((SplitCostContext *)context)->lz77->size * sizeof(size_t)))
__CPROVER_requires(__CPROVER_is_fresh(((SplitCostContext *)context)->lz77->ll_symbol, ((SplitCostContext *)context)->lz77->size * sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(((SplitCostContext *)context)->lz77->d_symbol, ((SplitCostContext *)context)->lz77->size * sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(((SplitCostContext *)context)->lz77->ll_counts, ZOPFLI_NUM_LL * sizeof(size_t)))
__CPROVER_requires(__CPROVER_is_fresh(((SplitCostContext *)context)->lz77->d_counts, ZOPFLI_NUM_D * sizeof(size_t)))
__CPROVER_requires(__CPROVER_forall { size_t k; (k < ((SplitCostContext *)context)->lz77->size) ==> ((SplitCostContext *)context)->lz77->ll_symbol[k] < ZOPFLI_NUM_LL })
__CPROVER_requires(__CPROVER_forall { size_t m; (m < ((SplitCostContext *)context)->lz77->size) ==> (((SplitCostContext *)context)->lz77->dists[m] == 0 || ((SplitCostContext *)context)->lz77->d_symbol[m] < ZOPFLI_NUM_D) })
__CPROVER_requires(__CPROVER_forall {
    size_t t; (((SplitCostContext *)context)->start <= t && t < ((SplitCostContext *)context)->end) ==>
        (((SplitCostContext *)context)->lz77->litlens[t] <= 258 &&
         (((SplitCostContext *)context)->lz77->dists[t] == 0 ||
          (((SplitCostContext *)context)->lz77->litlens[t] >= 3 && ((SplitCostContext *)context)->lz77->dists[t] <= 32768))) })
__CPROVER_assigns()
/* SplitCost sums two block-size estimates, each non-negative (0 for an empty
   range, >= 3 for a non-empty one), so the total is non-negative.  The mutant
   that subtracts the second estimate violates this whenever the first range is
   empty (0 - cost < 0). */
__CPROVER_ensures(__CPROVER_return_value >= 0)
/* Both ranges empty (i pinned to start == end): the sum is exactly 0. */
__CPROVER_ensures((i == ((SplitCostContext *)context)->start && i == ((SplitCostContext *)context)->end) ==> __CPROVER_return_value == 0)
/* Both ranges non-empty: each estimate is at least the 3-bit block header. */
__CPROVER_ensures((((SplitCostContext *)context)->start < i && i < ((SplitCostContext *)context)->end) ==> __CPROVER_return_value >= 6)
/* Exactly one range non-empty: a single header's worth of cost. */
__CPROVER_ensures(((i == ((SplitCostContext *)context)->start) != (i == ((SplitCostContext *)context)->end)) ==> __CPROVER_return_value >= 3)
/* clang-format on */
{
    SplitCostContext *c = (SplitCostContext *)context;
    return EstimateCost(c->lz77, c->start, i) + EstimateCost(c->lz77, i, c->end);
}

